module RefModule(
    input [7:0] d, 
    input load, 
    input clk, 
    output q
);
    reg [7:0] unused_shift_reg;

    always @(posedge clk) begin
        if (load)
            unused_shift_reg <= d;
        else
            unused_shift_reg <= unused_shift_reg >> 1;
    end

    assign q = unused_shift_reg[0];
endmodule
